// Extract guest info from webhook payload
const body = $input.first().json.body || $input.first().json;
const data = body.data || {};

return [{
  json: {
    guestName: data.guestName || data.guest || 'Valued Guest',
    email: data.email || '',
    checkOut: data.checkOut || '',
    loyaltyPoints: data.loyaltyPoints || 0,
    stayDuration: data.nights || 0,
    roomType: data.roomType || '',
    total: data.total || 0
  }
}];

// Build the thank-you / review request message
const guest = $input.first().json;

const message = `Hi ${guest.guestName},

Thank you for staying at Lina Point! We hope you had a wonderful time.

You earned ${guest.loyaltyPoints} loyalty points during your stay.

We'd love to hear about your experience. Your feedback helps us improve and helps other travelers discover Lina Point.

🌟 Leave a review: https://lina-point.vercel.app/review
🎁 Refer a friend and earn bonus points: https://lina-point.vercel.app/referral

We look forward to welcoming you back!

Warm regards,
The Lina Point Team`;

return [{
  json: {
    to: guest.email,
    subject: `Thank you for staying at Lina Point, ${guest.guestName}!`,
    message: message,
    guestName: guest.guestName
  }
}];

// Build referral reminder
const prev = $('Extract Guest Info').first().json;

const message = `Hi ${prev.guestName},

Just a friendly reminder — you have ${prev.loyaltyPoints} loyalty points waiting for you!

🎁 Share your unique referral link and earn 500 bonus points for every friend who books:
https://lina-point.vercel.app/referral

📸 Have photos from your trip? Tag us @LinaPointBelize on Instagram!

See you next time,
The Lina Point Team`;

return [{
  json: {
    to: prev.email,
    subject: `${prev.guestName}, your ${prev.loyaltyPoints} points are waiting!`,
    message: message,
    guestName: prev.guestName
  }
}];
